class StockSpanner {
    private int[] prices;
    private int index;

    public StockSpanner() {
        prices = new int[10001];
        index = -1;
    }

    public int next(int price) {
        index++;
        prices[index] = price;
        int span = 1;
        for (int i = index - 1; i >= 0; i--) {
            if (prices[i] <= price) {
                span++;
            } else {
                break;
            }
        }
        return span;
    }
}
```
